cat << 'EOF'
// In Program.cs

var builder = WebApplication.CreateBuilder(args);

// Register ProblemDetails services
builder.Services.AddProblemDetails(options =>
{
    options.CustomizeProblemDetails = context =>
    {
        context.ProblemDetails.Instance = context.HttpContext.Request.Path;
    };
});

var app = builder.Build();

// Use the exception handler middleware (replaces per-endpoint try-catch)
app.UseExceptionHandler(exceptionApp =>
{
    exceptionApp.Run(async context =>
    {
        var exception = context.Features.Get<Microsoft.AspNetCore.Diagnostics.IExceptionHandlerFeature>()?.Error;

        var (statusCode, title) = exception switch
        {
            KeyNotFoundException   => (StatusCodes.Status404NotFound, "Resource not found"),
            ArgumentException      => (StatusCodes.Status400BadRequest, "Invalid request"),
            InvalidOperationException => (StatusCodes.Status409Conflict, "Conflict"),
            _ => (StatusCodes.Status500InternalServerError, "An unexpected error occurred")
        };

        var problemDetails = new Microsoft.AspNetCore.Mvc.ProblemDetails
        {
            Status = statusCode,
            Title = title,
            Detail = statusCode == 500 ? null : exception?.Message,
            Instance = context.Request.Path
        };

        context.Response.StatusCode = statusCode;
        context.Response.ContentType = "application/problem+json";
        await context.Response.WriteAsJsonAsync(problemDetails);
    });
});

// Use status code pages for non-exception error responses (e.g., 404 from routing)
app.UseStatusCodePages();

// Example endpoints
app.MapGet("/items/{id}", (int id) =>
{
    if (id < 0) throw new ArgumentException("ID must be non-negative");
    if (id == 0) throw new KeyNotFoundException("Item not found");
    if (id == 99) throw new InvalidOperationException("Item is locked");
    return Results.Ok(new { Id = id, Name = "Widget" });
});

app.Run();
EOF

